          </button>
        </div>

        {/* Hidden List Area */}
        <div className={`space-y-3 overflow-hidden transition-all duration-500 ease-in-out ${isExpanded ? 'max-h-[800px] opacity-100 mb-6' : 'max-h-0 opacity-0'}`}>
